@page "/write-review"
@rendermode InteractiveServer
@using sv_64db6cf3a54f46758448b9daac1b67c6.Models
@using sv_64db6cf3a54f46758448b9daac1b67c6.Services
@using sv_64db6cf3a54f46758448b9daac1b67c6.Components.Shared
@inject ReviewService ReviewService

<h1>Write a Review</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your review has been submitted successfully.
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit">
        <DataAnnotationsValidator />
        <CustomValidator @ref="customValidator" />

        <div class="mb-3">
            <label class="form-label">Product Name</label>
            <InputText class="form-control" @bind-Value="Model.ProductName" />
            <ValidationMessage For="() => Model.ProductName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Rating</label>
            <InputNumber class="form-control" @bind-Value="Model.Rating" min="1" max="5" />
            <ValidationMessage For="() => Model.Rating" />
        </div>

        <div class="mb-3">
            <label class="form-label">Review Title</label>
            <InputText class="form-control" @bind-Value="Model.ReviewTitle" maxlength="100" />
            <ValidationMessage For="() => Model.ReviewTitle" />
        </div>

        <div class="mb-3">
            <label class="form-label">Review Body</label>
            <InputTextArea class="form-control" @bind-Value="Model.ReviewBody" rows="5" maxlength="2000" />
            <ValidationMessage For="() => Model.ReviewBody" />
        </div>

        <div class="mb-3">
            <label class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile OnChange="OnFilesSelected" multiple accept=".jpg,.jpeg,.png" class="form-control" />
            @if (fileErrors.Count > 0)
            {
                <ul class="text-danger mt-1">
                    @foreach (var error in fileErrors)
                    {
                        <li>@error</li>
                    }
                </ul>
            }
            @if (selectedFiles.Count > 0)
            {
                <ul class="mt-2">
                    @foreach (var file in selectedFiles)
                    {
                        <li>@file.Name — @FormatSize(file.Size)</li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Submit Review")
        </button>
    </EditForm>
}

@code {
    private ReviewModel Model { get; set; } = new();
    private CustomValidator? customValidator;
    private List<IBrowserFile> selectedFiles = new();
    private List<string> fileErrors = new();
    private bool isSubmitting;
    private bool submitted;

    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFileCount = 3;

    private void OnFilesSelected(InputFileChangeEventArgs e)
    {
        fileErrors.Clear();
        selectedFiles.Clear();

        var files = e.GetMultipleFiles(MaxFileCount + 1);

        if (files.Count > MaxFileCount)
        {
            fileErrors.Add($"You can upload at most {MaxFileCount} photos.");
            return;
        }

        foreach (var file in files)
        {
            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
            if (ext is not ".jpg" and not ".jpeg" and not ".png")
            {
                fileErrors.Add($"'{file.Name}' is not a supported format (JPG/PNG only).");
                continue;
            }

            if (file.Size > MaxFileSize)
            {
                fileErrors.Add($"'{file.Name}' exceeds the 5 MB limit.");
                continue;
            }

            selectedFiles.Add(file);
        }
    }

    private async Task HandleSubmit()
    {
        if (fileErrors.Count > 0)
            return;

        isSubmitting = true;
        try
        {
            var errors = await ReviewService.ValidateAndSubmitAsync(Model);
            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            // Process uploaded files (stub — read streams to confirm they're accessible)
            foreach (var file in selectedFiles)
            {
                await using var stream = file.OpenReadStream(maxAllowedSize: MaxFileSize);
                // Stub: save stream to storage
            }

            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes)
    {
        return bytes switch
        {
            < 1024 => $"{bytes} B",
            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
            _ => $"{bytes / (1024.0 * 1024.0):F2} MB"
        };
    }
}

